public int[] fix45(int[] nums) {
    int i = 0;
    while (i < nums.length && nums[i] != 4) {
        i++;
    }

    int j = 0;
    while (j < nums.length) {
        if (nums[j] == 5 && (j == 0 || nums[j - 1] != 4)) {
            break;
        }
        j++;
    }

    while (i < nums.length) {
        if (nums[i] == 4) {
            if (nums[i + 1] != 5) {
                int temp = nums[i + 1];
                nums[i + 1] = 5;
                nums[j] = temp;
            }
            i++;
            j++;
        } else {
            i++;
        }
    }

    return nums;
}

